//! `baton-metaquery` — search the iRODS catalog by AVU criteria.
//!
//! NDJSON in/out: each input line is a [`MetaqueryInput`] envelope; the
//! binary runs the query and emits each matching item as one output
//! line. Output items can be optionally decorated with the same
//! per-flag metadata that `baton-list` exposes, sharing
//! [`baton_rs::operations::list::enrich_with_metadata`].

use std::io::{BufRead, Write};

use anyhow::{Context, Result};
use baton_rs::operations::list::{enrich_with_metadata, EnrichOptions};
use baton_rs::operations::metaquery::{metaquery, MetaqueryFlags};
use baton_rs::types::MetaqueryInput;
use baton_rs::{RodsConnection, Target};
use clap::Parser;
use tracing_subscriber::EnvFilter;

#[derive(Parser, Debug)]
#[command(
    name = "baton-metaquery",
    about = "Search iRODS for data objects and collections matching AVU criteria"
)]
struct Args {
    /// Search for data objects only (default: both data objects and collections).
    #[arg(long)]
    obj: bool,

    /// Search for collections only (default: both data objects and collections).
    #[arg(long)]
    coll: bool,

    /// Include object size on each result (data objects only).
    #[arg(long)]
    size: bool,

    /// Include object checksum on each result (data objects only).
    #[arg(long)]
    checksum: bool,

    /// Include AVUs on each result.
    #[arg(long)]
    avu: bool,

    /// Include ACL entries on each result.
    #[arg(long)]
    acl: bool,

    /// Include replicate info on each result (data objects only).
    #[arg(long)]
    replicate: bool,

    /// Include timestamps on each result.
    #[arg(long)]
    timestamp: bool,

    /// Verbose logging (DEBUG level).
    #[arg(short, long, conflicts_with = "silent")]
    verbose: bool,

    /// Silent logging (ERROR level only).
    #[arg(long)]
    silent: bool,
}

impl Args {
    fn log_level(&self) -> &'static str {
        if self.silent {
            "error"
        } else if self.verbose {
            "debug"
        } else {
            "info"
        }
    }

    fn metaquery_flags(&self) -> MetaqueryFlags {
        // --obj alone narrows to data objects; --coll alone narrows to
        // collections; both flags or neither falls back to the
        // include-both default (matches baton's behaviour).
        if self.obj && !self.coll {
            MetaqueryFlags {
                include_data_objects: true,
                include_collections: false,
            }
        } else if self.coll && !self.obj {
            MetaqueryFlags {
                include_data_objects: false,
                include_collections: true,
            }
        } else {
            MetaqueryFlags::default()
        }
    }

    fn enrich_options(&self) -> EnrichOptions {
        EnrichOptions {
            avu: self.avu,
            acl: self.acl,
            replicate: self.replicate,
            timestamp: self.timestamp,
        }
    }
}

fn init_tracing(args: &Args) {
    let filter = EnvFilter::try_from_default_env()
        .unwrap_or_else(|_| EnvFilter::new(args.log_level()));
    tracing_subscriber::fmt()
        .with_env_filter(filter)
        .with_writer(std::io::stderr)
        .init();
}

/// Decorate one query result with the requested metadata fields.
/// On any iRODS-side failure during decoration, annotate the result
/// in-band rather than aborting the whole stream.
fn decorate_result(
    conn: &mut RodsConnection,
    mut target: Target,
    args: &Args,
) -> Target {
    // Size / checksum live on the stat path, not the catalog. Only run
    // the stat round-trip if either flag is set.
    if args.size || args.checksum {
        match conn.stat(&target.path()) {
            Ok(stat) => {
                if let Target::DataObject(d) = &mut target {
                    if args.size {
                        d.size = Some(stat.size);
                    }
                    if args.checksum && !stat.checksum.is_empty() {
                        d.checksum = Some(stat.checksum);
                    }
                }
            }
            Err(err) => {
                target.set_error(err);
                return target;
            }
        }
    }

    if let Err(err) = enrich_with_metadata(conn, &mut target, &args.enrich_options()) {
        target.set_error(err);
    }

    target
}

fn main() -> Result<()> {
    let args = Args::parse();
    init_tracing(&args);

    let flags = args.metaquery_flags();

    let mut conn = RodsConnection::connect_from_env().context("connecting to iRODS")?;
    conn.login_from_auth_file().context("authenticating")?;

    let stdin = std::io::stdin();
    let stdout = std::io::stdout();
    let mut out = stdout.lock();

    for line in stdin.lock().lines() {
        let line = line.context("reading stdin")?;
        if line.trim().is_empty() {
            continue;
        }

        let input: MetaqueryInput = serde_json::from_str(&line)
            .context("parsing input line as a MetaqueryInput")?;

        // metaquery() failures (bad scope, unsupported operator, server
        // error) currently propagate. The result-level loop below
        // continues past per-result decoration failures.
        let results = metaquery(&mut conn, &input, &flags)?;

        for target in results {
            let decorated = decorate_result(&mut conn, target, &args);
            serde_json::to_writer(&mut out, &decorated).context("writing output line")?;
            writeln!(&mut out).context("writing newline")?;
        }
    }

    Ok(())
}
